-- W1.6 questions batch 248/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-5ff21eeb-moex-00052', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲男與乙女結婚，育有一女6歲之丙，但因個性不合離婚，由乙對丙行使親權。其後乙認識丁， 丁對丙疼愛有加，丁經乙同意後，擬收養丙，向法院聲請認可。下列敘述，何者正確？', '["甲、乙離婚，乙取得親權，已可自行決定，丁收養丙，無須甲之同意", "甲、乙雖然離婚，但仍應經甲之同意，始得收養丙", "法院認可丙丁之收養契約時，無須考量丙之最佳利益", "丁收養丙必須與乙共同收養"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00053', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲於其父乙死亡後，傷心過度旋即死亡。乙死亡時未有配偶，遺有財產新臺幣（下同）1,200萬元， 甲另有同父異母姐姐丁。甲之子戊及女己，各得繼承多少財產？', '["300萬元", "400萬元", "600萬元", "不得繼承"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00054', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列何者得以遺囑指定應繼分？', '["滿14歲得法定代理人同意之未成年人", "18歲因酒醉無意識能力之人", "滿25歲受監護宣告之人", "滿30歲受輔助宣告之人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00055', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲、乙、丙三人合夥共同出資經營 A咖啡店，聘僱丁為店長，甲、乙、
丙均得以老闆之身分指揮監督丁。某日，丁在客人戊到 A咖啡店消費時，
利用為其準備飲料之機會，將安眠藥加入戊點用之飲品，丁並俟戊喝下
藥效發作後，再將戊扶至店外後方以預藏之水果刀殺害。今戊之母庚訴
請甲、乙、丙與丁連帶賠償其所支出之殯葬費、戊對庚之扶養費，以及
庚之精神慰撫金，是否有理？（15 分）若戊生前將其 B房地贈與辛，業
經辛允受，則於戊遭殺害後，其唯一繼承人壬對辛撤銷該贈與契約，是
否有理？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00056', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲乙等數人分別共有 A地，甲經其他共有人全體同意，在該地上興建 B
屋。乙嗣將其 A地之應有部分讓售予丙，已辦畢登記。丙隨即聲請法院
裁判分割 A地，法院判決確定該地應予變價分割，其後由丁拍定買受，
取得 A 地所有權全部。今丁向法院訴請甲拆除 B 屋及將該部分土地騰
空返還予自己，並訴請甲給付相當於租金之不當得利。對此，甲抗辯 B
屋乃基於地上權或租賃關係而座落在丁之 A地上，係屬有權占有且有法
律上原因。問丁之請求是否有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00057', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲向乙借款新臺幣100萬元，經過10年，甲向乙承認該筆借款存在。該承認之性質為何？', '["意思表示", "意思通知", "觀念通知", "感情表示"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00058', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '公同共有人依分產協議，而行使關於其分得所有權之移轉請求權時，該請求權之消滅時效期間為 幾年？', '["15年", "10年", "5年", "2年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00059', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於意思表示之敘述，何者正確？', '["法律行為，係乘他人之急迫、輕率或無經驗，使其為財產上給付或為給付之約定，毋待向法院 聲請撤銷，當然無效", "通謀虛偽意思表示而隱藏他項法律行為者，該二行為均無效", "單獨虛偽意思表示，不因之無效。但其情形為相對人明知者，則無效", "表意人受第三人之脅迫而為意思表示，如相對人為善意者，則不得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00060', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '依民法關於代理之規定，下列敘述何者正確？', '["代理人得自為意思表示與受意思表示，故代理人即視為本人", "代理人得為法律行為、準法律行為與事實行為", "意思表示瑕疵之認定，係完全就代理人決定之", "代理人所為或所受意思表示之效力，不因其為限制行為能力人而受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00061', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲到乙超商，以新臺幣50元硬幣一枚，購買一瓶礦泉水；甲付錢，乙給水，銀貨兩訖。整個交易 過程，下列敘述何者正確？', '["甲與乙超商雙方總共就只有訂立一個買賣契約", "甲與乙超商訂立一個買賣契約及一個物權契約", "甲與乙超商訂立一個買賣契約及二個物權契約", "甲與乙超商訂立一個買賣契約及三個物權契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
